func buildPodcastSEOAssets(transcript, titleSeed string, keywords []string) podcastSEOAssets {
	topic := strings.TrimSpace(titleSeed)
	if topic == "" {
		topic = firstWords(transcript, 8)
	}
	if topic == "" {
		topic = "Episode"
	}
	keywordText := strings.Join(keywords, ", ")
	if keywordText == "" {
		keywordText = topic
	}
	titles := []podcastSEOTitle{
		{Rank: 1, Title: titleCase(topic) + ": What Listeners Need to Know", Intent: "practical-search"},
		{Rank: 2, Title: "The Better Way to Think About " + topic, Intent: "thought-leadership"},
		{Rank: 3, Title: titleCase(topic) + " in Plain English", Intent: "explainer"},
	}
	quotes := podcastPullQuotes(transcript, 5)
	notes := fmt.Sprintf(`# %s

## Episode Summary

This episode explores %s with a focus on %s. The transcript package includes chapter markers, captions, title variants, and pull-quotes so the episode can be published with searchable, reusable metadata.

## Keywords

%s

## Suggested Description

A practical conversation about %s, built from the episode transcript and ready for podcast platforms, blog publication, and AI-assistant citation surfaces.
`, titles[0].Title, topic, keywordText, keywordText, topic)
	return podcastSEOAssets{Titles: titles, Quotes: quotes, Notes: notes}
}

func writePodcastSEOOutputs(outDir, transcript string, chapters []podcastChapter, assets podcastSEOAssets, opts podcastSEOOptions) error {
	if err := writeAtomicFile(filepath.Join(outDir, "transcript.txt"), []byte(strings.TrimSpace(transcript)+"\n")); err != nil {
		return err
	}
	blocks := transcriptBlocks(transcript)
	if err := writeAtomicFile(filepath.Join(outDir, "transcript.srt"), []byte(blocksToSRT(blocks))); err != nil {
		return err
	}
	if err := writeAtomicFile(filepath.Join(outDir, "transcript.vtt"), []byte("WEBVTT\n\n"+strings.ReplaceAll(blocksToSRT(blocks), ",", "."))); err != nil {
		return err
	}
	if err := writeJSONFile(filepath.Join(outDir, "chapters.json"), chapters); err != nil {
		return err
	}
	if err := writeAtomicFile(filepath.Join(outDir, "show-notes.md"), []byte(assets.Notes)); err != nil {
		return err
	}
	if err := writeJSONFile(filepath.Join(outDir, "titles.json"), assets.Titles); err != nil {
		return err
	}
	if err := writeJSONFile(filepath.Join(outDir, "quotes.json"), assets.Quotes); err != nil {
		return err
	}
	prompt := map[string]any{
		"llm_model":   opts.LLMModel,
		"title_seed":  opts.TitleSeed,
		"keywords":    splitComma(opts.Keywords),
		"instruction": "Use the transcript, real timings, and keywords to refine show notes, chapters, titles, and pull-quotes. Do not invent timestamps.",
	}
	return writeJSONFile(filepath.Join(outDir, "seo-prompt.json"), prompt)
}

func podcastChaptersFromTranscript(transcript string) []podcastChapter {
	blocks := transcriptBlocks(transcript)
	if len(blocks) == 0 {
		return nil
	}
	chapters := []podcastChapter{{StartTime: 0, Title: "Opening"}}
	if len(blocks) > 2 {
		chapters = append(chapters, podcastChapter{StartTime: 60, Title: "Main Ideas"})
	}
	if len(blocks) > 5 {
		chapters = append(chapters, podcastChapter{StartTime: float64((len(blocks) - 2) * 30), Title: "Closing"})
	}
	return chapters
}

func transcriptBlocks(transcript string) []string {
	var blocks []string
	for _, raw := range strings.Split(transcript, "\n") {
		line := strings.TrimSpace(raw)
		if line != "" {
			blocks = append(blocks, line)
		}
	}
	if len(blocks) == 0 && strings.TrimSpace(transcript) != "" {
		blocks = append(blocks, strings.TrimSpace(transcript))
	}
	return blocks
}

func blocksToSRT(blocks []string) string {
	var b strings.Builder
	for i, block := range blocks {
		start := float64(i * 30)
		end := start + 30
		fmt.Fprintf(&b, "%d\n%s --> %s\n%s\n\n", i+1, formatSRTTime(start), formatSRTTime(end), block)
	}
	return b.String()
}

func podcastPullQuotes(transcript string, limit int) []podcastSEOPullQuote {
	sentences := splitSentences(transcript)
	var quotes []podcastSEOPullQuote
	for _, sentence := range sentences {
		words := strings.Fields(sentence)
		if len(words) < 6 || len(words) > 32 {
			continue
		}
		quotes = append(quotes, podcastSEOPullQuote{Index: len(quotes) + 1, Quote: sentence})
		if len(quotes) >= limit {
			break
		}
	}
	if len(quotes) == 0 && strings.TrimSpace(transcript) != "" {
		quotes = append(quotes, podcastSEOPullQuote{Index: 1, Quote: firstWords(transcript, 24)})
	}
	return quotes
}

func splitSentences(text string) []string {
	var out []string
	var current strings.Builder
	for _, r := range text {
		current.WriteRune(r)
		if r == '.' || r == '!' || r == '?' {
			if sentence := strings.TrimSpace(current.String()); sentence != "" {
				out = append(out, sentence)
			}
			current.Reset()
		}
	}
	if sentence := strings.TrimSpace(current.String()); sentence != "" {
		out = append(out, sentence)
	}
	return out
}

func firstWords(text string, limit int) string {
	words := strings.Fields(text)
	if len(words) > limit {
		words = words[:limit]
	}
	return strings.Join(words, " ")
}

func titleCase(text string) string {
	words := strings.Fields(text)
	for i, word := range words {
		if word == "" {
			continue
		}
		words[i] = strings.ToUpper(word[:1]) + word[1:]
	}
	return strings.Join(words, " ")
}

func rawJSONText(data json.RawMessage) string {
	var obj map[string]any
	if err := json.Unmarshal(data, &obj); err != nil {
		return ""
	}
	if text, _ := obj["text"].(string); text != "" {
		return text
	}
	return ""
}
